package com.restaurantcraft.entity;
import com.restaurantcraft.blockentity.*; import com.restaurantcraft.config.RestaurantCraftConfig; import com.restaurantcraft.data.*; import com.restaurantcraft.entity.ai.*; import com.restaurantcraft.menu.CustomerOrderMenu; import com.restaurantcraft.registry.ModItems; import com.restaurantcraft.util.RestaurantCustomerUtil; import net.minecraft.core.BlockPos; import net.minecraft.nbt.CompoundTag; import net.minecraft.network.chat.Component; import net.minecraft.server.level.ServerPlayer; import net.minecraft.sounds.*; import net.minecraft.world.*; import net.minecraft.world.item.ItemStack; import net.minecraftforge.network.NetworkHooks; import net.minecraft.world.entity.*; import net.minecraft.world.entity.ai.attributes.AttributeSupplier; import net.minecraft.world.entity.ai.attributes.Attributes; import net.minecraft.world.entity.ai.goal.*; import net.minecraft.world.entity.animal.Animal; import net.minecraft.world.entity.player.Player; import net.minecraft.world.inventory.AbstractContainerMenu; import net.minecraft.world.level.Level; import net.minecraft.world.level.block.entity.BlockEntity; import org.jetbrains.annotations.Nullable; import java.util.*;
public class CustomerEntity extends PathfinderMob implements MenuProvider { private BlockPos restaurantBlockPos,targetChairPos,targetExitPos; private String orderedDishId=""; public int orderDeadlineTicks,seatWaitTicks,afterEatWaitTicks; private CustomerState state=CustomerState.SPAWNED; public CustomerEntity(EntityType<? extends PathfinderMob> t, Level l){super(t,l);} public static AttributeSupplier.Builder createAttributes(){return PathfinderMob.createMobAttributes().add(Attributes.MAX_HEALTH,20.0D).add(Attributes.MOVEMENT_SPEED,0.28D).add(Attributes.FOLLOW_RANGE,32.0D);} protected void registerGoals(){goalSelector.addGoal(1,new FloatGoal(this));goalSelector.addGoal(2,new FindRestaurantSeatGoal(this));goalSelector.addGoal(3,new CustomerWaitOrderGoal(this));goalSelector.addGoal(4,new MoveToRestaurantExitGoal(this));goalSelector.addGoal(8,new RandomStrollGoal(this,0.8));goalSelector.addGoal(9,new LookAtPlayerGoal(this,Player.class,6));}
 public Component getDisplayName(){return Component.translatable("entity.restaurant_craft.customer");} public Component getName(){ if(state==CustomerState.WAITING_FOR_ORDER&&!orderedDishId.isBlank()){var d=DishRegistry.byId(orderedDishId); return Component.literal("需要: "+d.map(DishDefinition::zhName).orElse(orderedDishId)+" 剩余: "+Math.max(0,orderDeadlineTicks/20)+"秒");} return super.getName();} public boolean isCustomNameVisible(){return state==CustomerState.WAITING_FOR_ORDER;} public void tick(){super.tick(); if(!level().isClientSide){ if(state==CustomerState.SPAWNED)state=CustomerState.FINDING_SEAT; if(state==CustomerState.FINDING_SEAT && ++seatWaitTicks>RestaurantCraftConfig.seatSearchTimeoutSeconds.get()*20) failAndLeave(false); if(state==CustomerState.WAITING_FOR_ORDER && --orderDeadlineTicks<=0) failAndLeave(false); if(state==CustomerState.ORDER_COMPLETED && ++afterEatWaitTicks>=RestaurantCraftConfig.afterOrderSuccessLeaveSeconds.get()*20) leave(); if(state==CustomerState.LEAVING&&targetExitPos!=null&&blockPosition().closerThan(targetExitPos,2.2)) discard(); }}
 public void assignRestaurant(BlockPos p){restaurantBlockPos=p;state=CustomerState.FINDING_SEAT;} public BlockPos restaurantPos(){return restaurantBlockPos;} public CustomerState state(){return state;} public BlockPos chairPos(){return targetChairPos;} public BlockPos exitPos(){return targetExitPos;} public void setChair(BlockPos p){targetChairPos=p;} public void sitAndOrder(){ if(state!=CustomerState.FINDING_SEAT)return; state=CustomerState.WAITING_FOR_ORDER; List<DishDefinition> list=restaurant().map(RestaurantManagementBlockEntity::validRecipes).orElse(List.of()); if(list.isEmpty()) {failAndLeave(false);return;} DishDefinition d=list.get(random.nextInt(list.size())); orderedDishId=d.id(); orderDeadlineTicks=d.tier().seconds*20; setCustomNameVisible(true);}
 public Optional<RestaurantManagementBlockEntity> restaurant(){ if(restaurantBlockPos==null)return Optional.empty(); BlockEntity be=level().getBlockEntity(restaurantBlockPos); return be instanceof RestaurantManagementBlockEntity r?Optional.of(r):Optional.empty();}
 public InteractionResult mobInteract(Player p, InteractionHand h){ if(!level().isClientSide && p instanceof ServerPlayer sp && state==CustomerState.WAITING_FOR_ORDER) NetworkHooks.openScreen(sp,this,buf->buf.writeInt(getId())); return InteractionResult.sidedSuccess(level().isClientSide); } public Component getDisplayNameForMenu(){return getDisplayName();} @Nullable public AbstractContainerMenu createMenu(int id, net.minecraft.world.entity.player.Inventory inv, Player p){return new CustomerOrderMenu(id,inv,getId());}
 public void submitDish(ServerPlayer p){ ItemStack held=p.containerMenu instanceof CustomerOrderMenu m?m.input.getItem(0):ItemStack.EMPTY; if(held.isEmpty())return; if(DishRegistry.byId(orderedDishId).isPresent()&&held.is(ModItems.COOKED_DISH_ITEMS.get(orderedDishId).get())){held.shrink(1); DishDefinition d=DishRegistry.byId(orderedDishId).get(); restaurant().ifPresent(r->r.onCustomerSucceeded(this,d)); releaseChair(); state=CustomerState.ORDER_COMPLETED; afterEatWaitTicks=0; p.displayClientMessage(Component.translatable("message.restaurant_craft.order_success"),true);} else p.displayClientMessage(Component.translatable("message.restaurant_craft.wrong_dish"),true); }
 public void leave(){state=CustomerState.LEAVING; targetExitPos=restaurant().map(r->r.data.exitPos).orElse(blockPosition()); releaseChair();} public void failAndLeave(boolean mopped){ if(state==CustomerState.FAILED||state==CustomerState.REMOVED)return; state=CustomerState.FAILED; releaseChair(); restaurant().ifPresent(RestaurantManagementBlockEntity::onCustomerFailed); level().playSound(null,blockPosition(),SoundEvents.VILLAGER_NO,SoundSource.NEUTRAL,1,1); discard();} public boolean canBeMoppedBy(Player p){return restaurant().map(r->r.isOwner(p)).orElse(false);} private void releaseChair(){ if(targetChairPos!=null&&level().getBlockEntity(targetChairPos) instanceof RestaurantChairBlockEntity c)c.setOccupied(false);}
 public void addAdditionalSaveData(CompoundTag t){super.addAdditionalSaveData(t); if(restaurantBlockPos!=null)t.putLong("Restaurant",restaurantBlockPos.asLong()); if(targetChairPos!=null)t.putLong("Chair",targetChairPos.asLong()); if(targetExitPos!=null)t.putLong("Exit",targetExitPos.asLong()); t.putString("Dish",orderedDishId);t.putInt("Deadline",orderDeadlineTicks);t.putInt("SeatWait",seatWaitTicks);t.putInt("AfterEat",afterEatWaitTicks);t.putString("State",state.name());} public void readAdditionalSaveData(CompoundTag t){super.readAdditionalSaveData(t); if(t.contains("Restaurant"))restaurantBlockPos=BlockPos.of(t.getLong("Restaurant")); if(t.contains("Chair"))targetChairPos=BlockPos.of(t.getLong("Chair")); if(t.contains("Exit"))targetExitPos=BlockPos.of(t.getLong("Exit")); orderedDishId=t.getString("Dish");orderDeadlineTicks=t.getInt("Deadline");seatWaitTicks=t.getInt("SeatWait");afterEatWaitTicks=t.getInt("AfterEat"); try{state=CustomerState.valueOf(t.getString("State"));}catch(Exception ignored){state=CustomerState.SPAWNED;}} }
